export const RANKS: RankDef[] = [
  { id: "npc", name: "NPC", minAura: 0, emoji: "😶" },
  { id: "soft-launch", name: "Soft Launch", minAura: 200, emoji: "✨" },
  { id: "plot-armor", name: "Plot Armor", minAura: 600, emoji: "🛡️" },
  { id: "main-character", name: "Main Character", minAura: 1500, emoji: "🎬" },
  { id: "aura-farmer", name: "Aura Farmer", minAura: 3500, emoji: "🌾" },
  { id: "vibe-curator", name: "Vibe Curator", minAura: 7000, emoji: "🔮" },
  { id: "aura-lord", name: "Aura Lord", minAura: 12000, emoji: "👑" },
];

export function rankForAura(totalAura: number): RankDef {
  let current = RANKS[0]!;
  for (const rank of RANKS) {
    if (totalAura >= rank.minAura) current = rank;
  }
  return current;
}

export function nextRank(totalAura: number): RankDef | null {
  for (const rank of RANKS) {
    if (totalAura < rank.minAura) return rank;
  }
  return null;
}

import { CHALLENGES } from "../data/challenges";
import type { Challenge } from "../types";
import { pickDaily } from "../utils/seed";

export function getTodaysChallenge(date = new Date()): Challenge {
  return pickDaily(CHALLENGES, "challenge-v1", date);
}

export function getPracticeChallenge(): Challenge {
  // Slightly different salt so practice ≠ daily when same session
  return pickDaily(CHALLENGES, `practice-${Date.now() % 7}`, new Date());
}

import type { Challenge, ScoreResult } from "../types";

export interface DuelPlayer {
  name: string;
  answer: string;
  result: ScoreResult | null;
}

export type DuelPhase = "setup" | "p1" | "handoff" | "p2" | "result";

export interface DuelState {
  phase: DuelPhase;
  challenge: Challenge | null;
  p1: DuelPlayer;
  p2: DuelPlayer;
}

export function createDuelState(): DuelState {
  return {
    phase: "setup",
    challenge: null,
    p1: { name: "Player 1", answer: "", result: null },
    p2: { name: "Player 2", answer: "", result: null },
  };
}

export function duelWinner(d: DuelState): "p1" | "p2" | "tie" | null {
  if (!d.p1.result || !d.p2.result) return null;
  if (d.p1.result.score === d.p2.result.score) return "tie";
  return d.p1.result.score > d.p2.result.score ? "p1" : "p2";
}

import { BATTLE_PASS, cosmeticById } from "../data/cosmetics";
import type { PlayerState } from "../types";
import { saveState } from "../state/store";
import { todayKey } from "../utils/seed";
import type { ScoreResult } from "../types";

export function applyDailyResult(state: PlayerState, result: ScoreResult, challengeId: string): PlayerState {
  const today = todayKey();
  const isFirstToday = state.lastDailyDate !== today;

  let streak = state.streak;
  if (isFirstToday) {
    if (!state.lastPlayDate) {
      streak = 1;
    } else if (state.lastPlayDate === today) {
      streak = Math.max(1, state.streak);
    } else {
      const last = new Date(state.lastPlayDate + "T12:00:00");
      const now = new Date(today + "T12:00:00");
      const diff = Math.round((now.getTime() - last.getTime()) / 86_400_000);
      streak = diff === 1 ? state.streak + 1 : 1;
    }
  }

  const ownedCores = result.coreDropped
    ? Array.from(new Set([...state.ownedCores, result.coreDropped]))
    : state.ownedCores;

  // Battle pass XP: roughly score/25 levels toward next
  const xpGain = isFirstToday ? Math.max(1, Math.floor(result.score / 28)) : 0;
  const battlePassLevel = Math.min(10, state.battlePassLevel + xpGain);

  const next: PlayerState = {
    ...state,
    totalAura: state.totalAura + result.score,
    sparks: state.sparks + result.sparksEarned,
    streak,
    lastPlayDate: today,
    lastDailyDate: isFirstToday ? today : state.lastDailyDate,
    ownedCores,
    battlePassLevel,
    bestDailyScore: Math.max(state.bestDailyScore, result.score),
    history: [
      { date: today, score: result.score, challengeId },
      ...state.history,
    ].slice(0, 30),
  };
  saveState(next);
  return next;
}

export function applyPracticeResult(state: PlayerState, result: ScoreResult): PlayerState {
  const next: PlayerState = {
    ...state,
    totalAura: state.totalAura + Math.round(result.score * 0.35),
    sparks: state.sparks + Math.max(3, Math.round(result.sparksEarned * 0.4)),
    ownedCores: result.coreDropped
      ? Array.from(new Set([...state.ownedCores, result.coreDropped]))
      : state.ownedCores,
  };
  saveState(next);
  return next;
}

export function buyCosmetic(
  state: PlayerState,
  cosmeticId: string,
  currency: "sparks" | "glow",
): { ok: true; state: PlayerState } | { ok: false; reason: string } {
  const item = cosmeticById(cosmeticId);
  if (!item) return { ok: false, reason: "Item not found." };
  if (state.ownedCosmetics.includes(cosmeticId)) {
    return { ok: false, reason: "Already owned." };
  }

  if (currency === "sparks") {
    if (item.priceSparks <= 0 && item.priceGlow > 0) {
      return { ok: false, reason: "Glow-only item." };
    }
    if (state.sparks < item.priceSparks) return { ok: false, reason: "Not enough Sparks." };
    const next: PlayerState = {
      ...state,
      sparks: state.sparks - item.priceSparks,
      ownedCosmetics: [...state.ownedCosmetics, cosmeticId],
    };
    saveState(next);
    return { ok: true, state: next };
  }

  const cost = item.priceGlow > 0 ? item.priceGlow : Math.ceil(item.priceSparks / 8);
  if (cost <= 0) return { ok: false, reason: "Free item — already unlocked." };
  if (state.glow < cost) return { ok: false, reason: "Not enough Glow." };
  const next: PlayerState = {
    ...state,
    glow: state.glow - cost,
    ownedCosmetics: [...state.ownedCosmetics, cosmeticId],
  };
  saveState(next);
  return { ok: true, state: next };
}

export function equipCosmetic(state: PlayerState, cosmeticId: string): PlayerState {
  const item = cosmeticById(cosmeticId);
  if (!item || !state.ownedCosmetics.includes(cosmeticId)) return state;
  const next: PlayerState = {
    ...state,
    equipped: { ...state.equipped, [item.slot]: cosmeticId },
  };
  saveState(next);
  return next;
}

/** Mock IAP — demo monetization path */
export function buyGlowPack(
  state: PlayerState,
  pack: "starter" | "hype" | "mogul",
): PlayerState {
  const packs = {
    starter: { glow: 40, sparks: 50 },
    hype: { glow: 120, sparks: 150 },
    mogul: { glow: 300, sparks: 400 },
  } as const;
  const p = packs[pack];
  const next: PlayerState = {
    ...state,
    glow: state.glow + p.glow,
    sparks: state.sparks + p.sparks,
  };
  saveState(next);
  return next;
}

export function unlockBattlePassPremium(state: PlayerState): PlayerState {
  if (state.battlePassPremium) return state;
  // Mock purchase — free in demo, or cost 50 glow if they have it, else just unlock
  const next: PlayerState = {
    ...state,
    battlePassPremium: true,
    glow: state.glow >= 50 ? state.glow - 50 : state.glow,
  };
  saveState(next);
  return next;
}

export function claimBattlePassTier(
  state: PlayerState,
  level: number,
  track: "free" | "premium",
): { ok: true; state: PlayerState; label: string } | { ok: false; reason: string } {
  const tier = BATTLE_PASS.find((t) => t.level === level);
  if (!tier) return { ok: false, reason: "Invalid tier." };
  if (state.battlePassLevel < level) return { ok: false, reason: "Level not reached." };

  if (track === "free") {
    if (state.claimedFreeTiers.includes(level)) return { ok: false, reason: "Already claimed." };
    const reward = tier.freeReward;
    let next = applyReward(state, reward);
    next = {
      ...next,
      claimedFreeTiers: [...next.claimedFreeTiers, level],
    };
    saveState(next);
    return { ok: true, state: next, label: reward.label };
  }

  if (!state.battlePassPremium) return { ok: false, reason: "Premium pass required." };
  if (state.claimedPremiumTiers.includes(level)) return { ok: false, reason: "Already claimed." };
  const reward = tier.premiumReward;
  let next = applyReward(state, reward);
  next = {
    ...next,
    claimedPremiumTiers: [...next.claimedPremiumTiers, level],
  };
  saveState(next);
  return { ok: true, state: next, label: reward.label };
}

function applyReward(
  state: PlayerState,
  reward: { type: string; id?: string; amount?: number },
): PlayerState {
  if (reward.type === "sparks") {
    return { ...state, sparks: state.sparks + (reward.amount ?? 0) };
  }
  if (reward.type === "glow") {
    return { ...state, glow: state.glow + (reward.amount ?? 0) };
  }
  if (reward.type === "cosmetic" && reward.id) {
    if (state.ownedCosmetics.includes(reward.id)) return state;
    return { ...state, ownedCosmetics: [...state.ownedCosmetics, reward.id] };
  }
  if (reward.type === "core" && reward.id) {
    if (state.ownedCores.includes(reward.id)) return state;
    return { ...state, ownedCores: [...state.ownedCores, reward.id] };
  }
  return state;
}

export function applyDuelWin(state: PlayerState, score: number): PlayerState {
  const next: PlayerState = {
    ...state,
    duelWins: state.duelWins + 1,
    totalAura: state.totalAura + Math.round(score * 0.5),
    sparks: state.sparks + 25 + Math.floor(score / 5),
  };
  saveState(next);
  return next;
}

export function applyDuelLoss(state: PlayerState, score: number): PlayerState {
  const next: PlayerState = {
    ...state,
    totalAura: state.totalAura + Math.round(score * 0.2),
    sparks: state.sparks + 8,
  };
  saveState(next);
  return next;
}

import { aestheticById } from "../data/aesthetics";
import { CORES } from "../data/cores";
import type { AestheticCore, Challenge, ScoreResult } from "../types";
import { clamp } from "../utils/format";
import { hashString, mulberry32 } from "../utils/seed";

const SLANG = [
  "aura",
  "rizz",
  "no cap",
  "fr",
  "vibe",
  "vibes",
  "locked in",
  "main character",
  "slay",
  "iconic",
  "lowkey",
  "highkey",
  "ate",
  "served",
  "core",
  "aesthetic",
  "unhinged",
  "delulu",
  "understood the assignment",
  "it's giving",
  "period",
  "bet",
  "goat",
  "drip",
  "fit",
  "soft launch",
  "plot twist",
  "npc",
  "w",
  "l",
];

const VERDICTS_HIGH = [
  "Main character energy secured.",
  "The aura is loud and correct.",
  "You understood the assignment.",
  "Certified vibe curator behavior.",
  "Plot armor activated.",
];

const VERDICTS_MID = [
  "Solid aura. Room to glow up.",
  "Respectable vibe. Push the drama.",
  "Cute. Now make it cinematic.",
  "Base aura locked. Season 2 pending.",
];

const VERDICTS_LOW = [
  "NPC chapter. Rewrite the scene.",
  "Aura buffering… try more personality.",
  "Quiet launch. Louder next time.",
  "The assignment is still waiting.",
];

function countHits(text: string, words: string[]): number {
  const lower = text.toLowerCase();
  return words.reduce((n, w) => (lower.includes(w) ? n + 1 : n), 0);
}

function uniquenessScore(text: string): number {
  const words = text.toLowerCase().split(/\s+/).filter(Boolean);
  if (words.length === 0) return 0;
  const unique = new Set(words);
  return unique.size / words.length;
}

export function scoreLocal(
  answer: string,
  challenge: Challenge,
  core: AestheticCore,
  streak: number,
): Omit<ScoreResult, "sparksEarned" | "coreDropped" | "streakBonus"> {
  const trimmed = answer.trim();
  const len = trimmed.length;
  const aesthetic = aestheticById(core);

  let score = 28;

  // Length sweet spot
  if (len >= 12 && len <= 40) score += 10;
  else if (len > 40 && len <= 160) score += 22;
  else if (len > 160 && len <= 280) score += 18;
  else if (len > 280) score += 8;
  else if (len > 0) score += 4;

  // Aesthetic keyword fit
  const keyHits = countHits(trimmed, aesthetic.keywords);
  score += Math.min(18, keyHits * 6);

  // Slang / culture lexicon
  const slangHits = countHits(trimmed, SLANG);
  score += Math.min(16, slangHits * 4);

  // Category nudges
  if (challenge.category === "rizz" && /[?!]/.test(trimmed)) score += 4;
  if (challenge.category === "caption" && len <= 80 && len >= 8) score += 6;
  if (challenge.category === "main-character" && /\b(i|my|me)\b/i.test(trimmed)) score += 4;

  // Craft signals
  score += Math.round(uniquenessScore(trimmed) * 12);
  if (/[,:—–-]/.test(trimmed)) score += 3;
  if ((trimmed.match(/[.!?]/g) || []).length >= 1) score += 2;

  // Penalties
  if (len < 8) score -= 20;
  if (/^(.)\1{6,}$/.test(trimmed)) score -= 30;
  if (trimmed === trimmed.toUpperCase() && len > 12) score -= 10;
  if (/https?:\/\//i.test(trimmed)) score -= 8;
  const words = trimmed.split(/\s+/);
  if (words.length > 3 && new Set(words.map((w) => w.toLowerCase())).size === 1) score -= 25;

  // Tiny seeded variance so same answer isn't always identical vibe
  const rng = mulberry32(hashString(`${challenge.id}:${trimmed.toLowerCase()}`));
  score += Math.floor(rng() * 7) - 2;

  score = clamp(Math.round(score), 5, 98);

  // Streak presentation boost (capped) applied later for sparks; slight score flair
  const streakTouch = Math.min(4, Math.floor(streak / 2));
  score = clamp(score + streakTouch, 5, 99);

  let verdictPool = VERDICTS_MID;
  if (score >= 80) verdictPool = VERDICTS_HIGH;
  else if (score < 45) verdictPool = VERDICTS_LOW;
  const verdict = verdictPool[Math.floor(rng() * verdictPool.length)]!;

  const tags: string[] = [aesthetic.label];
  if (slangHits > 0) tags.push("slang-locked");
  if (keyHits > 0) tags.push("core-fit");
  if (score >= 85) tags.push("viral");
  else if (score >= 65) tags.push("glow-up");
  else tags.push("soft-launch");
  if (challenge.category === "rizz") tags.push("rizz");

  return {
    score,
    verdict,
    tags: tags.slice(0, 4),
    source: "local",
  };
}

export function finalizeRewards(
  base: Omit<ScoreResult, "sparksEarned" | "coreDropped" | "streakBonus">,
  streak: number,
  ownedCores: string[],
): ScoreResult {
  const streakBonus = Math.min(0.35, streak * 0.05);
  const sparksEarned = Math.max(
    8,
    Math.round(base.score * 0.45 * (1 + streakBonus) + streak * 2),
  );

  let coreDropped: string | null = null;
  const dropRoll = mulberry32(hashString(`drop:${base.score}:${Date.now()}`))();
  const dropChance =
    base.score >= 90 ? 0.55 : base.score >= 75 ? 0.28 : base.score >= 55 ? 0.12 : 0.04;

  if (dropRoll < dropChance) {
    const pool =
      base.score >= 92
        ? CORES.filter((c) => c.rarity === "legendary" || c.rarity === "epic")
        : base.score >= 80
          ? CORES.filter((c) => c.rarity === "epic" || c.rarity === "rare")
          : CORES.filter((c) => c.rarity === "rare" || c.rarity === "common");
    const unowned = pool.filter((c) => !ownedCores.includes(c.id));
    const pickFrom = unowned.length ? unowned : pool;
    coreDropped = pickFrom[Math.floor(dropRoll * pickFrom.length * 10) % pickFrom.length]!.id;
  }

  return {
    ...base,
    sparksEarned,
    coreDropped,
    streakBonus,
  };
}

import { createClient, type SupabaseClient } from "@supabase/supabase-js";

const url = import.meta.env.VITE_SUPABASE_URL as string | undefined;
const anonKey = import.meta.env.VITE_SUPABASE_ANON_KEY as string | undefined;

export function isSupabaseConfigured(): boolean {
  return Boolean(url && anonKey && url.startsWith("http") && anonKey.length > 20);
}

export function getSupabaseConfigError(): string | null {
  if (isSupabaseConfigured()) return null;
  return "Cloud backend is not configured. Set VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY (see README).";
}

let client: SupabaseClient | null = null;

export function getSupabase(): SupabaseClient {
  if (!isSupabaseConfigured()) {
    throw new Error(getSupabaseConfigError() ?? "Supabase not configured");
  }
  if (!client) {
    client = createClient(url!, anonKey!, {
      auth: {
        persistSession: true,
        autoRefreshToken: true,
        detectSessionInUrl: true,
        storage: localStorage,
      },
    });
  }
  return client;
}

