import "./style.css";
import { checkAiAvailable } from "./ai/judge";
import {
  getCachedSession,
  logout,
  restoreSession,
  type Session,
} from "./auth/auth";
import { createDefaultState, flushSave, loadState, refreshStreak, resetState } from "./state/store";
import type { PlayerState, Screen } from "./types";
import { renderCard } from "./ui/card";
import { renderDuel } from "./ui/duel";
import { renderHome } from "./ui/home";
import { renderLogin } from "./ui/login";
import { renderOnboarding } from "./ui/onboarding";
import { renderPlay } from "./ui/play";
import { mountInShell } from "./ui/shell";
import { renderShop } from "./ui/shop";

const app = document.querySelector<HTMLDivElement>("#app")!;

let session: Session | null = null;
let state: PlayerState = createDefaultState();
let screen: Screen = "home";
let aiOn = false;
let booting = true;

function showBoot(message: string): void {
  app.innerHTML = `
    <div class="onboarding" style="justify-content:center;align-items:center;text-align:center">
      <div class="logo">AuraFarm</div>
      <p class="muted" style="margin-top:16px">${message}</p>
    </div>
  `;
}

async function initAi(): Promise<void> {
  aiOn = await checkAiAvailable();
  if (!booting && session && state.onboarded && screen === "home") render();
}

async function setState(next: PlayerState): Promise<void> {
  state = next;
  render();
}

function navigate(next: Screen): void {
  screen = next;
  render();
}

async function handleLogout(): Promise<void> {
  showBoot("Signing out…");
  await flushSave();
  await logout();
  session = null;
  state = createDefaultState();
  screen = "home";
  render();
}

async function handleAuthed(next: Session): Promise<void> {
  session = next;
  showBoot("Loading your farm…");
  state = refreshStreak(await loadState());
  screen = "home";
  render();
}

function render(): void {
  if (booting) {
    showBoot("Connecting…");
    return;
  }

  if (!session) {
    renderLogin(app, (s) => {
      void handleAuthed(s);
    });
    return;
  }

  if (!state.onboarded) {
    renderOnboarding(
      app,
      state,
      (next) => {
        state = next;
        render();
      },
      () => {
        void handleLogout();
      },
    );
    return;
  }

  mountInShell(
    app,
    state,
    screen,
    (slot) => {
      switch (screen) {
        case "home":
          renderHome(slot, state, navigate, aiOn, () => {
            void handleLogout();
          });
          break;
        case "play":
          renderPlay(slot, state, aiOn, (s) => {
            void setState(s);
          });
          break;
        case "shop":
          renderShop(slot, state, (s) => {
            void setState(s);
          });
          break;
        case "card":
          renderCard(slot, state);
          break;
        case "duel":
          renderDuel(slot, state, (s) => {
            void setState(s);
          });
          break;
      }
    },
    navigate,
  );
}

window.addEventListener("aurafarm:nav", ((e: CustomEvent<Screen>) => {
  navigate(e.detail);
}) as EventListener);

(window as unknown as { aurafarmReset: () => void }).aurafarmReset = () => {
  if (!getCachedSession()) return;
  state = resetState();
  screen = "home";
  render();
};

(window as unknown as { aurafarmLogout: () => void }).aurafarmLogout = () => {
  void handleLogout();
};

async function boot(): Promise<void> {
  showBoot("Connecting…");
  try {
    session = await restoreSession();
    if (session) {
      state = refreshStreak(await loadState());
    } else {
      state = createDefaultState();
    }
  } catch (e) {
    console.error(e);
    session = null;
    state = createDefaultState();
  }
  booting = false;
  render();
  void initAi();
}

void boot();

import { getCachedSession } from "../auth/auth";
import { FREE_DEFAULTS } from "../data/cosmetics";
import { getSupabase, isSupabaseConfigured } from "../lib/supabase";
import type { AestheticCore, EquippedCosmetics, PlayerState } from "../types";
import { todayKey } from "../utils/seed";

const defaultEquipped: EquippedCosmetics = {
  frame: "frame-basic",
  aura: "aura-soft",
  nameplate: "name-plain",
  background: "bg-void",
};

function cacheKey(userId: string): string {
  return `aurafarm.cloudcache.v1:${userId}`;
}

export function createDefaultState(): PlayerState {
  return {
    version: 1,
    displayName: "",
    core: "main-character",
    totalAura: 0,
    sparks: 80,
    glow: 0,
    streak: 0,
    lastPlayDate: null,
    lastDailyDate: null,
    ownedCosmetics: [...FREE_DEFAULTS],
    equipped: { ...defaultEquipped },
    ownedCores: ["spark-seed"],
    battlePassLevel: 0,
    battlePassPremium: false,
    claimedFreeTiers: [],
    claimedPremiumTiers: [],
    bestDailyScore: 0,
    duelWins: 0,
    onboarded: false,
    history: [],
  };
}

export function normalizeState(parsed: Partial<PlayerState> | null | undefined): PlayerState {
  const base = createDefaultState();
  if (!parsed || typeof parsed !== "object") return base;
  return {
    ...base,
    ...parsed,
    version: 1,
    ownedCosmetics: Array.from(
      new Set([...(parsed.ownedCosmetics ?? []), ...FREE_DEFAULTS]),
    ),
    equipped: { ...defaultEquipped, ...(parsed.equipped ?? {}) },
    ownedCores: parsed.ownedCores?.length ? parsed.ownedCores : base.ownedCores,
    claimedFreeTiers: parsed.claimedFreeTiers ?? [],
    claimedPremiumTiers: parsed.claimedPremiumTiers ?? [],
    history: parsed.history ?? [],
  };
}

function readLocalCache(userId: string): PlayerState | null {
  try {
    const raw = localStorage.getItem(cacheKey(userId));
    if (!raw) return null;
    return normalizeState(JSON.parse(raw) as Partial<PlayerState>);
  } catch {
    return null;
  }
}

function writeLocalCache(userId: string, state: PlayerState): void {
  localStorage.setItem(cacheKey(userId), JSON.stringify(state));
}

let saveTimer: ReturnType<typeof setTimeout> | null = null;
let pendingState: PlayerState | null = null;
let cloudSyncError: string | null = null;

export function getCloudSyncError(): string | null {
  return cloudSyncError;
}

/** Load player state from Supabase (with local cache fallback). */
export async function loadState(): Promise<PlayerState> {
  const session = getCachedSession();
  if (!session) return createDefaultState();

  const cached = readLocalCache(session.userId);

  if (!isSupabaseConfigured()) {
    return cached ?? createDefaultState();
  }

  try {
    const sb = getSupabase();
    const { data, error } = await sb
      .from("profiles")
      .select("game_state, display_name, username, updated_at")
      .eq("user_id", session.userId)
      .maybeSingle();

    if (error) {
      console.warn("loadState cloud error", error.message);
      cloudSyncError = error.message;
      return cached ?? createDefaultState();
    }

    if (!data) {
      const fresh = cached ?? createDefaultState();
      writeLocalCache(session.userId, fresh);
      await pushStateToCloud(session.userId, fresh, session.username);
      return fresh;
    }

    const remote = normalizeState(data.game_state as Partial<PlayerState>);
    // Prefer non-empty cloud state; if cloud is empty default, keep cache if more advanced
    const remoteEmpty = !remote.onboarded && remote.totalAura === 0 && remote.sparks === 80;
    if (remoteEmpty && cached && (cached.onboarded || cached.totalAura > 0)) {
      await pushStateToCloud(session.userId, cached, session.username);
      cloudSyncError = null;
      return cached;
    }

    if (!remote.displayName && data.display_name) {
      remote.displayName = data.display_name;
    }
    writeLocalCache(session.userId, remote);
    cloudSyncError = null;
    return remote;
  } catch (e) {
    cloudSyncError = e instanceof Error ? e.message : "Cloud load failed";
    return cached ?? createDefaultState();
  }
}

async function pushStateToCloud(
  userId: string,
  state: PlayerState,
  username: string,
): Promise<void> {
  if (!isSupabaseConfigured()) return;
  const sb = getSupabase();
  const { error } = await sb.from("profiles").upsert(
    {
      user_id: userId,
      username,
      email: getCachedSession()?.email ?? "",
      display_name: state.displayName || username,
      game_state: state,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "user_id" },
  );
  if (error) {
    cloudSyncError = error.message;
    console.warn("cloud save failed", error.message);
  } else {
    cloudSyncError = null;
  }
}

/** Immediate local cache + debounced cloud upsert. */
export function saveState(state: PlayerState): void {
  const session = getCachedSession();
  if (!session) return;

  writeLocalCache(session.userId, state);
  pendingState = state;

  if (saveTimer) clearTimeout(saveTimer);
  saveTimer = setTimeout(() => {
    const toSave = pendingState;
    pendingState = null;
    saveTimer = null;
    if (!toSave) return;
    void pushStateToCloud(session.userId, toSave, session.username);
  }, 400);
}

/** Flush pending cloud save (call before logout). */
export async function flushSave(): Promise<void> {
  if (saveTimer) {
    clearTimeout(saveTimer);
    saveTimer = null;
  }
  const session = getCachedSession();
  const toSave = pendingState;
  pendingState = null;
  if (session && toSave) {
    await pushStateToCloud(session.userId, toSave, session.username);
  }
}

export function resetState(): PlayerState {
  const s = createDefaultState();
  saveState(s);
  return s;
}

export function completeOnboarding(
  state: PlayerState,
  name: string,
  core: AestheticCore,
): PlayerState {
  const next: PlayerState = {
    ...state,
    displayName: name.trim().slice(0, 18) || "Aura Rookie",
    core,
    onboarded: true,
  };
  saveState(next);
  return next;
}

export function refreshStreak(state: PlayerState): PlayerState {
  const today = todayKey();
  if (!state.lastPlayDate) {
    return state;
  }
  if (state.lastPlayDate === today) {
    return state;
  }

  const last = new Date(state.lastPlayDate + "T12:00:00");
  const now = new Date(today + "T12:00:00");
  const diffDays = Math.round((now.getTime() - last.getTime()) / 86_400_000);

  const next: PlayerState = {
    ...state,
    streak: diffDays === 1 ? state.streak : 0,
  };
  saveState(next);
  return next;
}

export function hasPlayedDaily(state: PlayerState): boolean {
  return state.lastDailyDate === todayKey();
}

