import { getTodaysChallenge } from "../game/daily";
import { applyDuelLoss, applyDuelWin } from "../game/economy";
import {
  createDuelState,
  duelWinner,
  type DuelState,
} from "../game/duel";
import { finalizeRewards, scoreLocal } from "../game/scorer";
import { saveState } from "../state/store";
import type { PlayerState } from "../types";
import { escapeHtml } from "../utils/format";
import { showToast } from "./toast";

export function renderDuel(
  container: HTMLElement,
  state: PlayerState,
  onState: (s: PlayerState) => void,
): void {
  let duel: DuelState = createDuelState();

  const paint = () => {
    if (duel.phase === "setup") {
      container.innerHTML = `
        <div class="card">
          <h2 style="margin:0 0 8px">Aura Duel</h2>
          <p class="muted" style="margin:0">Pass-and-play. Same prompt. Higher aura wins Sparks. Perfect for siblings, friends, or chaotic group hangs.</p>
          <div class="field" style="margin-top:14px">
            <label for="p1">Player 1 name</label>
            <input id="p1" maxlength="16" value="${escapeHtml(state.displayName || "Player 1")}" />
          </div>
          <div class="field" style="margin-top:10px">
            <label for="p2">Player 2 name</label>
            <input id="p2" maxlength="16" value="Challenger" />
          </div>
          <button class="btn btn-primary" id="start-duel" style="margin-top:14px">Start duel</button>
        </div>
      `;
      container.querySelector("#start-duel")?.addEventListener("click", () => {
        const p1 = (container.querySelector("#p1") as HTMLInputElement).value.trim() || "Player 1";
        const p2 = (container.querySelector("#p2") as HTMLInputElement).value.trim() || "Player 2";
        duel = {
          ...createDuelState(),
          phase: "p1",
          challenge: getTodaysChallenge(),
          p1: { name: p1, answer: "", result: null },
          p2: { name: p2, answer: "", result: null },
        };
        paint();
      });
      return;
    }

    if (duel.phase === "handoff") {
      container.innerHTML = `
        <div class="card handoff">
          <div class="big">👀</div>
          <h2>Pass the phone</h2>
          <p class="muted">${escapeHtml(duel.p1.name)} is done. Hide the screen and hand it to <strong>${escapeHtml(duel.p2.name)}</strong>.</p>
          <button class="btn btn-primary" id="p2-ready">${escapeHtml(duel.p2.name)} is ready</button>
        </div>
      `;
      container.querySelector("#p2-ready")?.addEventListener("click", () => {
        duel = { ...duel, phase: "p2" };
        paint();
      });
      return;
    }

    if (duel.phase === "result" && duel.p1.result && duel.p2.result) {
      const winner = duelWinner(duel);
      container.innerHTML = `
        <div class="card result-panel">
          <div class="muted" style="font-weight:700">DUEL RESULT</div>
          <div class="hero-score" style="font-size:2.2rem">
            ${
              winner === "tie"
                ? "TIE"
                : winner === "p1"
                  ? escapeHtml(duel.p1.name)
                  : escapeHtml(duel.p2.name)
            }
          </div>
          <p class="verdict">${winner === "tie" ? "Split aura. Both ate." : "takes the aura crown."}</p>
          <div class="stat-grid">
            <div class="stat"><b>${duel.p1.result.score}</b><span>${escapeHtml(duel.p1.name)}</span></div>
            <div class="stat"><b>VS</b><span>aura</span></div>
            <div class="stat"><b>${duel.p2.result.score}</b><span>${escapeHtml(duel.p2.name)}</span></div>
          </div>
          <div class="card" style="margin-top:12px;text-align:left">
            <p class="muted" style="margin:0 0 6px"><strong>${escapeHtml(duel.p1.name)}</strong> — ${escapeHtml(duel.p1.result.verdict)}</p>
            <p class="muted" style="margin:0"><strong>${escapeHtml(duel.p2.name)}</strong> — ${escapeHtml(duel.p2.result.verdict)}</p>
          </div>
          <div class="btn-row">
            <button class="btn btn-primary" id="rematch">Rematch</button>
            <button class="btn btn-secondary" id="duel-home">Done</button>
          </div>
        </div>
      `;
      container.querySelector("#rematch")?.addEventListener("click", () => {
        duel = createDuelState();
        paint();
      });
      container.querySelector("#duel-home")?.addEventListener("click", () => {
        window.dispatchEvent(new CustomEvent("aurafarm:nav", { detail: "home" }));
      });
      return;
    }

    // p1 or p2 answer
    const isP1 = duel.phase === "p1";
    const player = isP1 ? duel.p1 : duel.p2;
    const challenge = duel.challenge!;

    container.innerHTML = `
      <div class="card">
        <div class="muted" style="font-weight:700">${isP1 ? "PLAYER 1" : "PLAYER 2"} · ${escapeHtml(player.name)}</div>
        <div class="challenge-emoji">${challenge.emoji}</div>
        <h2 style="margin:0 0 6px">${escapeHtml(challenge.title)}</h2>
        <p class="muted" style="margin:0">${escapeHtml(challenge.prompt)}</p>
      </div>
      <div class="card" style="margin-top:12px">
        <div class="field">
          <label for="duel-answer">Your line</label>
          <textarea id="duel-answer" maxlength="400" placeholder="Make it hit..."></textarea>
        </div>
        <button class="btn btn-primary" id="lock-in">Lock in answer</button>
      </div>
    `;

    container.querySelector("#lock-in")?.addEventListener("click", () => {
      const answer = (container.querySelector("#duel-answer") as HTMLTextAreaElement).value;
      if (answer.trim().length < 3) {
        showToast("Need a real answer (3+ chars).");
        return;
      }
      const base = scoreLocal(answer, challenge, state.core, state.streak);
      const full = finalizeRewards(base, state.streak, state.ownedCores);

      if (isP1) {
        duel = {
          ...duel,
          p1: { ...duel.p1, answer, result: full },
          phase: "handoff",
        };
        paint();
        return;
      }

      duel = {
        ...duel,
        p2: { ...duel.p2, answer, result: full },
        phase: "result",
      };

      // Host profile (device owner) gets rewards from the duel outcome.
      const w = duelWinner(duel);
      let next = state;
      if (w === "p1") next = applyDuelWin(state, duel.p1.result!.score);
      else if (w === "p2") next = applyDuelLoss(state, duel.p1.result!.score);
      else {
        next = applyDuelLoss(
          state,
          Math.round((duel.p1.result!.score + duel.p2.result!.score) / 2),
        );
        next = { ...next, sparks: next.sparks + 10 };
        saveState(next);
      }
      onState(next);
      state = next;
      showToast(w === "p1" ? `${duel.p1.name} wins!` : w === "p2" ? `${duel.p2.name} wins!` : "Tie!");
      paint();
    });
  };

  paint();
}

import {
  login,
  register,
  type AuthResult,
  type Session,
} from "../auth/auth";
import { getSupabaseConfigError, isSupabaseConfigured } from "../lib/supabase";
import { escapeHtml } from "../utils/format";

export function renderLogin(
  root: HTMLElement,
  onAuthed: (session: Session) => void,
): void {
  let mode: "login" | "register" = "login";
  let error = "";
  let busy = false;
  const configError = getSupabaseConfigError();

  const paint = () => {
    root.innerHTML = `
      <div class="onboarding auth-screen">
        <div>
          <div class="logo">AuraFarm</div>
          <p class="muted" style="margin:10px 0 0">Farm your aura. Flex your vibe.<br/>Cloud account — play on phone &amp; PC. 13+</p>
        </div>

        ${
          configError
            ? `<div class="card"><p class="danger-text" style="margin:0">${escapeHtml(configError)}</p>
               <p class="muted" style="margin:10px 0 0;font-size:0.82rem">Create a free Supabase project, run <code>supabase/schema.sql</code>, and set env vars (see README). Redeploy / restart dev after.</p></div>`
            : ""
        }

        <div class="card stack">
          <div class="tabs-inline">
            <button type="button" data-mode="login" class="${mode === "login" ? "active" : ""}">Log in</button>
            <button type="button" data-mode="register" class="${mode === "register" ? "active" : ""}">Sign up</button>
          </div>

          <form id="auth-form" class="stack" autocomplete="on">
            ${
              mode === "register"
                ? `
              <div class="field">
                <label for="email">Email</label>
                <input id="email" name="email" type="email" maxlength="120" autocomplete="email" placeholder="you@email.com" required />
              </div>
              <div class="field">
                <label for="username">Username</label>
                <input id="username" name="username" maxlength="20" autocomplete="username" placeholder="e.g. vibe_curator" spellcheck="false" required />
              </div>
            `
                : `
              <div class="field">
                <label for="identifier">Email or username</label>
                <input id="identifier" name="identifier" maxlength="120" autocomplete="username" placeholder="you@email.com or vibe_curator" spellcheck="false" required />
              </div>
            `
            }
            <div class="field">
              <label for="password">Password</label>
              <input
                id="password"
                name="password"
                type="password"
                maxlength="72"
                autocomplete="${mode === "register" ? "new-password" : "current-password"}"
                placeholder="${mode === "register" ? "min 6 characters" : "••••••••"}"
                required
              />
            </div>
            ${
              mode === "register"
                ? `
              <div class="field">
                <label for="password2">Confirm password</label>
                <input id="password2" name="password2" type="password" maxlength="72" autocomplete="new-password" placeholder="repeat password" required />
              </div>
            `
                : ""
            }

            ${error ? `<p class="danger-text" role="alert">${escapeHtml(error)}</p>` : ""}

            <button class="btn btn-primary" type="submit" ${busy || !isSupabaseConfigured() ? "disabled" : ""}>
              ${busy ? "Working..." : mode === "login" ? "Log in →" : "Create account →"}
            </button>
          </form>

          <p class="muted" style="font-size:0.78rem;margin:0">
            Progress syncs online so you can hop between phone and PC.
            Cosmetics &amp; Glow packs are demo economy (no real charges).
          </p>
        </div>
      </div>
    `;

    root.querySelectorAll<HTMLButtonElement>("[data-mode]").forEach((btn) => {
      btn.addEventListener("click", () => {
        mode = btn.dataset.mode as "login" | "register";
        error = "";
        paint();
      });
    });

    const form = root.querySelector("#auth-form") as HTMLFormElement | null;
    form?.addEventListener("submit", async (e) => {
      e.preventDefault();
      if (busy || !isSupabaseConfigured()) return;

      const password = (root.querySelector("#password") as HTMLInputElement).value;
      let email = "";
      let username = "";
      let identifier = "";

      if (mode === "register") {
        email = (root.querySelector("#email") as HTMLInputElement).value;
        username = (root.querySelector("#username") as HTMLInputElement).value;
        const password2 = (root.querySelector("#password2") as HTMLInputElement).value;
        if (password !== password2) {
          error = "Passwords do not match.";
          paint();
          return;
        }
      } else {
        identifier = (root.querySelector("#identifier") as HTMLInputElement).value;
      }

      busy = true;
      error = "";
      paint();

      // restore fields after repaint
      if (mode === "register") {
        const em = root.querySelector("#email") as HTMLInputElement | null;
        const un = root.querySelector("#username") as HTMLInputElement | null;
        const pw = root.querySelector("#password") as HTMLInputElement | null;
        const p2 = root.querySelector("#password2") as HTMLInputElement | null;
        if (em) em.value = email;
        if (un) un.value = username;
        if (pw) pw.value = password;
        if (p2) p2.value = password;
      } else {
        const id = root.querySelector("#identifier") as HTMLInputElement | null;
        const pw = root.querySelector("#password") as HTMLInputElement | null;
        if (id) id.value = identifier;
        if (pw) pw.value = password;
      }

      let result: AuthResult;
      try {
        result =
          mode === "login"
            ? await login(identifier, password)
            : await register(email, username, password);
      } catch (err) {
        result = {
          ok: false,
          error: err instanceof Error ? err.message : "Something went wrong. Try again.",
        };
      }

      busy = false;
      if (!result.ok) {
        error = result.error;
        paint();
        if (mode === "register") {
          const em = root.querySelector("#email") as HTMLInputElement | null;
          const un = root.querySelector("#username") as HTMLInputElement | null;
          if (em) em.value = email;
          if (un) un.value = username;
        } else {
          const id = root.querySelector("#identifier") as HTMLInputElement | null;
          if (id) id.value = identifier;
        }
        return;
      }

      onAuthed(result.session);
    });
  };

  paint();
}

